function resolve_fullscreen_target(shell) {
    // 不使用 iframe 原生全屏：手机界面需与 Hub 同文档层叠
    return shell;
}
function is_browser_fullscreen() {
    try {
        if (document.fullscreenElement)
            return true;
        if (window.parent !== window && window.parent.document.fullscreenElement === window.frameElement)
            return true;
    }
    catch {
        /* cross-origin */
    }
    return false;
}
export function useHubFullscreen(shell_ref) {
    const is_fullscreen = ref(false);
    const is_expanded = ref(false);
    async function exit_fullscreen() {
        is_expanded.value = false;
        const tasks = [];
        if (document.fullscreenElement) {
            tasks.push(document.exitFullscreen().then(() => undefined).catch(() => undefined));
        }
        try {
            if (window.parent !== window && window.parent.document.fullscreenElement) {
                tasks.push(window.parent.document.exitFullscreen().then(() => undefined).catch(() => undefined));
            }
        }
        catch {
            /* ignore */
        }
        if (tasks.length)
            await Promise.all(tasks);
    }
    async function toggle_fullscreen() {
        if (is_fullscreen.value) {
            is_fullscreen.value = false;
            await exit_fullscreen();
            return;
        }
        is_fullscreen.value = true;
        const target = resolve_fullscreen_target(shell_ref.value);
        if (!target) {
            is_expanded.value = true;
            return;
        }
        try {
            await target.requestFullscreen();
            if (is_browser_fullscreen()) {
                is_expanded.value = false;
                return;
            }
        }
        catch (error) {
            console.info('[鸣潮伪同层] 浏览器全屏不可用，使用页面内全屏', error);
        }
        is_expanded.value = true;
    }
    function on_fullscreen_change() {
        if (is_browser_fullscreen()) {
            is_fullscreen.value = true;
            is_expanded.value = false;
            return;
        }
        if (is_expanded.value) {
            is_fullscreen.value = true;
            return;
        }
        is_fullscreen.value = false;
    }
    onMounted(() => {
        $(document).on('fullscreenchange.wuwaHub webkitfullscreenchange.wuwaHub', on_fullscreen_change);
        try {
            if (window.parent !== window) {
                window.parent.document.addEventListener('fullscreenchange', on_fullscreen_change);
                window.parent.document.addEventListener('webkitfullscreenchange', on_fullscreen_change);
            }
        }
        catch {
            /* ignore */
        }
    });
    onUnmounted(() => {
        $(document).off('fullscreenchange.wuwaHub webkitfullscreenchange.wuwaHub');
        try {
            if (window.parent !== window) {
                window.parent.document.removeEventListener('fullscreenchange', on_fullscreen_change);
                window.parent.document.removeEventListener('webkitfullscreenchange', on_fullscreen_change);
            }
        }
        catch {
            /* ignore */
        }
        void exit_fullscreen();
    });
    return { is_fullscreen, is_expanded, toggle_fullscreen };
}
